SELECT n.*, ste.site_nm AS site_nm, cd_nt.code_label AS notice_type_cd_nm FROM sy_notice n LEFT JOIN sy_site ste ON ste.site_id = n.site_id LEFT JOIN sy_code cd_nt ON cd_nt.code_grp = 'NOTICE_TYPE' AND cd_nt.code_value = n.notice_type_cd
ORDER BY n.notice_id ASC ORDER BY n.notice_id DESC ORDER BY n.notice_title ASC ORDER BY n.notice_title DESC ORDER BY n.reg_date ASC ORDER BY n.reg_date DESC ORDER BY n.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

