ORDER BY n.notice_id ASC ORDER BY n.notice_id DESC ORDER BY n.notice_title ASC ORDER BY n.notice_title DESC ORDER BY n.reg_date ASC ORDER BY n.reg_date DESC ORDER BY n.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

