site_id = #{siteId}, notice_title = #{noticeTitle}, notice_type_cd = #{noticeTypeCd}, is_fixed = #{isFixed}, content_html = #{contentHtml}, attach_grp_id = #{attachGrpId}, start_date = #{startDate}, end_date = #{endDate}, notice_status_cd = #{noticeStatusCd}, view_count = #{viewCount}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE notice_id = #{noticeId}
